(function(){"use strict";document.querySelectorAll("form").forEach(function(n){n.addEventListener("submit",function(){var t=n.querySelector('[type="submit"]');t&&!t.disabled&&(typeof $=="undefined"||!$(n).data("validator")||$(n).valid())&&(t.setAttribute("data-original-html",t.innerHTML),t.disabled=!0,t.innerHTML='<span class="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"><\/span>Processing...')})});document.querySelectorAll(".toast").forEach(function(n){bootstrap.Toast.getOrCreateInstance(n).show()});window.addEventListener("pageshow",function(n){n.persisted&&document.querySelectorAll("[data-original-html]").forEach(function(n){n.innerHTML=n.getAttribute("data-original-html");n.disabled=!1;n.removeAttribute("data-original-html")})})})();